from google_adk import Agent
from vex_sdk import VexMonitor

def detect_auth_propagation_failures(agent_call):
    response = agent_call.execute()
    if response.status_code in [401, 403]:
        monitor = VexMonitor('auth-propagation')
        monitor.log({
            'agent_id': agent_call.agent.id,
            'parent_id': agent_call.parent_agent.id,
            'endpoint': response.url,
            'error': response.text[:200]
        })
        return {'issue': 'AUTH_PROPAGATION_FAILURE'}
    return None

import time
from google_adk.sessions import SessionState

def detect_token_drift(session: SessionState):
    current_token = session.get_auth_token()
    token_age = time.time() - current_token['issued_at']

    if token_age > 3300:  # 55 minutes
        return {
            'issue': 'TOKEN_EXPIRED',
            'age_seconds': token_age,
            'model_context': session.current_model
        }

    if session.model_switched_recently():
        return {'issue': 'MODEL_SWITCH_TOKEN_LOSS'}
    return None

import re
from google_adk.tools import ToolResponse

def detect_tool_auth_errors(tool_response: ToolResponse):
    error_patterns = [
        r'401 Unauthorized',
        r'403 Forbidden',
        r'invalid_token',
        r'access_denied'
    ]

    content = tool_response.content
    for pattern in error_patterns:
        if re.search(pattern, content, re.IGNORECASE):
            return {
                'issue': 'TOOL_AUTH_FAILURE',
                'tool_name': tool_response.tool.name,
                'agent_chain': tool_response.agent_hierarchy,
                'snippet': content[:100]
            }
    return None

