from google_adk import Agent
from google.oauth2 import service_account

class AuthPropagator:
    def __init__(self):
        self.credentials = service_account.Credentials.from_service_account_file(
            'agent-service-account.json'
        )

    def before_agent_callback(self, agent: Agent, context):
        # Propagate credentials to child agents
        context['auth'] = {
            'token': self.credentials.token,
            'scopes': self.credentials.scopes,
            'expiry': self.credentials.expiry
        }
        agent.session.update_auth(context['auth'])

# Register with ADK
propagator = AuthPropagator()
agent_runner.add_before_agent_callback(propagator.before_agent_callback)

from google_adk.sessions import SessionManager

class TokenRefresher:
    def before_model_switch(self, session: SessionManager, new_model):
        token = session.get_auth_token()
        if self._needs_refresh(token):
            refreshed = token.refresh()
            session.update_auth({
                'token': refreshed.token,
                'issued_at': time.time(),
                'expiry': refreshed.expiry
            })

    def _needs_refresh(self, token):
        return time.time() > token['expiry'] - 300  # Refresh 5 min early

# Integrate with session manager
session_manager.add_pre_switch_hook(TokenRefresher().before_model_switch)

from google_adk.tools import ToolResponse

class AuthErrorNormalizer:
    def handle_tool_response(self, response: ToolResponse):
        if self._is_auth_error(response):
            return ToolResponse(
                tool=response.tool,
                content={
                    'error': 'AUTH_REQUIRED',
                    'status': response.status_code,
                    'retry_with_auth': True,
                    'required_scopes': self._extract_scopes(response)
                },
                structured=True
            )
        return response

    def _is_auth_error(self, response):
        return response.status_code in [401, 403]

# Register as tool response handler
tool_handler.add_response_processor(AuthErrorNormalizer().handle_tool_response)

