from vex_sdk import Vex
from google_adk import AgentRunner

# Install: pip install google-adk vex-sdk

vex = Vex(api_key="your-vex-api-key")

@vex.monitor("agent-auth")
def auth_guardian(agent_call):
    # Vex auto-detects auth patterns in ADK
    issues = vex.scan_agent_auth(
        agent_call=agent_call,
        session=agent_call.session,
        delegation_chain=agent_call.hierarchy
    )

    if issues:
        vex.auto_fix({
            'propagate_credentials': True,
            'refresh_tokens': True,
            'normalize_responses': True
        })
        return {'remediated': True}

# Zero-config integration
runner = AgentRunner()
runner.add_before_agent_callback(vex.auth_monitor)
runner.start()
